"use strict";
function maxWidthRamp(nums) {
    let maxRamp = 0;
    for (let i = 0; i < nums.length; i++) {
        for (let j = i + 1; j < nums.length; j++) {
            if (nums[i] <= nums[j]) {
                maxRamp = Math.max(maxRamp, j - i);
            }
        }
    }
    return maxRamp;
}
